import { useContext } from 'react';
import { ThemeContext } from './ThemeContext';

function Header() {
  const theme = useContext(ThemeContext);
  // theme is whatever value the nearest ThemeContext.Provider supplies
  return (
    <header className={theme === 'dark' ? 'header-dark' : 'header-light'}>
      <h1>My App</h1>
    </header>
  );
}

const AppContext = createContext(null);

function App() {
  const [user, setUser] = useState({ name: 'Alice' });
  const [count, setCount] = useState(0);

  return (
    // value changes whenever user OR count changes
    <AppContext.Provider value={{ user, setUser, count, setCount }}>
      <UserDisplay />
    </AppContext.Provider>
  );
}

function UserDisplay() {
  const { user } = useContext(AppContext); // destructures only user
  // BUT re-renders whenever count changes too — still subscribed to full value
  return <p>{user.name}</p>;
}

// ✓ Split by concern — UserDisplay only re-renders when user changes
const UserContext  = createContext(null);
const CountContext = createContext(null);

function UserDisplay() {
  const { user } = useContext(UserContext); // only subscribes to user
  return <p>{user.name}</p>;
}

const ThemeContext = createContext(null); // default: null

// Rendered without a Provider:
function Orphan() {
  const ctx = useContext(ThemeContext);
  console.log(ctx); // null — the default value
  return <p>No provider above me</p>;
}

// Custom hook with guard:
export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme: no ThemeProvider found in tree');
  return ctx;
}

function ThemeToggle() {
  const { theme, setTheme } = useContext(ThemeContext);
  // same as:
  // const ctx = useContext(ThemeContext);
  // const theme = ctx.theme;
  // const setTheme = ctx.setTheme;

  return (
    <button
      onClick={() => setTheme(t => t === 'light' ? 'dark' : 'light')}
    >
      Mode: {theme}
    </button>
  );
}

function NavBar() {
  const { user }  = useContext(AuthContext);  // subscription 1
  const { theme } = useContext(ThemeContext); // subscription 2
  const { t }     = useContext(LocaleContext);// subscription 3

  return (
    <nav className={theme}>
      <span>{t('welcome')}, {user?.name}</span>
    </nav>
  );
}

// Legacy Consumer API (before hooks)
function UserBadge() {
  return (
    <UserContext.Consumer>
      {user => <span>{user?.name ?? 'Guest'}</span>}
    </UserContext.Consumer>
  );
}

// Modern useContext (same result, cleaner code)
function UserBadge() {
  const user = useContext(UserContext);
  return <span>{user?.name ?? 'Guest'}</span>;
}

// ✗ Wrong: conditional call
function Conditional({ isAdmin }) {
  if (isAdmin) {
    const ctx = useContext(AdminContext); // rule violation
  }
  return <p>Hello</p>;
}

// ✓ Correct: always call, conditionally use
function Conditional({ isAdmin }) {
  const ctx = useContext(AdminContext); // always called
  if (!isAdmin) return <p>Hello</p>;
  return <p>Admin: {ctx.panel}</p>;
}

// High-frequency value (mouse position) — avoid global context
const MouseContext = createContext({ x: 0, y: 0 });

function MouseTracker({ children }) {
  const [pos, setPos] = useState({ x: 0, y: 0 });
  // Mousemove fires hundreds of times per second.
  // Every useContext(MouseContext) call re-renders on every event.
  // Components that read only x (not y) still re-render on y changes.

  // Alternative: pass the value through props to only the components that need it,
  // or use a library like Zustand/Jotai that supports granular subscriptions.
  return (
    <MouseContext.Provider value={pos}>
      {children}
    </MouseContext.Provider>
  );
}

import { render, screen } from '@testing-library/react';
import { ThemeProvider } from './ThemeContext';
import { Header } from './Header';

// Wrap in Provider for each test
test('renders dark header', () => {
  render(
    <ThemeProvider initialTheme="dark">
      <Header />
    </ThemeProvider>
  );
  expect(screen.getByRole('banner')).toHaveClass('header-dark');
});

// Test utility: wrap with all required providers
function renderWithProviders(ui, { theme = 'light', user = null } = {}) {
  return render(
    <ThemeProvider initialTheme={theme}>
      <AuthProvider initialUser={user}>
        {ui}
      </AuthProvider>
    </ThemeProvider>
  );
}

// Usage in tests:
test('shows username when logged in', () => {
  renderWithProviders(<NavBar />, { user: { name: 'Alice' } });
  expect(screen.getByText('Alice')).toBeInTheDocument();
});

// Set displayName so DevTools labels it clearly:
const ThemeContext = createContext(null);
ThemeContext.displayName = 'ThemeContext';

// In DevTools, the Hooks panel for a consumer shows:
// Context ThemeContext
//   value: { theme: 'dark', setTheme: ƒ }

// Without displayName it shows:
// Context
//   value: { theme: 'dark', setTheme: ƒ }

function Counter() {
  const { count } = useContext(CountContext);
  // count is always the current value — re-read on every render
  // Unlike useEffect, there is no dep array and no risk of stale capture

  return <p>{count}</p>;
}

// Composition alternative to context for some cases:
// Instead of drilling 'user' prop three levels:

function App() {
  const [user] = useState({ name: 'Alice' });
  // Pass <Avatar user={user} /> as a prop — no prop drilling:
  return <Layout avatar={<Avatar user={user} />} />;
}

function Layout({ avatar }) {
  return <Sidebar avatar={avatar} />; // passes the element, not the data
}

function Sidebar({ avatar }) {
  return <header>{avatar}</header>; // renders it without knowing about user
}

import { lazy, Suspense } from 'react';
const HeavyWidget = lazy(() => import('./HeavyWidget'));

function App() {
  return (
    <ThemeContext.Provider value="dark">
      <Suspense fallback={<p>Loading...</p>}>
        <HeavyWidget />
        {/* HeavyWidget.js can call useContext(ThemeContext) normally */}
      </Suspense>
    </ThemeContext.Provider>
  );
}

// ✗ React.memo does NOT prevent context-triggered re-renders
const HeavyList = React.memo(function HeavyList() {
  const { theme } = useContext(ThemeContext);
  // Re-renders whenever ThemeContext value changes — memo is bypassed
  return <ul>{/* expensive list */}</ul>;
});

// ✓ Pull context up, pass as prop — memo applies
function ThemeConsumer() {
  const { theme } = useContext(ThemeContext); // re-renders on theme change
  return <HeavyList theme={theme} />;         // passes stable primitive
}

const HeavyList = React.memo(function HeavyList({ theme }) {
  // Re-renders only when `theme` prop actually changes
  return <ul className={theme}>{/* expensive list */}</ul>;
});

function SyncEffect() {
  const { user } = useContext(AuthContext);

  useEffect(() => {
    if (user) {
      analytics.identify(user.id); // read context value inside effect
    }
  }, [user]); // user is a dep — effect re-runs when user changes

  return null;
}
